using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API.
/// Uses constructor injection — HttpClient and ILogger are resolved via DI
/// and never appear in the tool schema sent to the LLM.
/// </summary>
[McpServerToolType]
public class JsonPlaceholderTools(HttpClient httpClient, ILogger<JsonPlaceholderTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a post by its ID from the JSONPlaceholder API.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post (1–100)")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {PostId}", postId);
        var json = await httpClient.GetStringAsync($"posts/{postId}", cancellationToken);
        return json;
    }

    [McpServerTool, Description("List posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts to this user ID (omit for all posts)")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"posts?userId={userId}" : "posts";
        logger.LogInformation("Listing posts: {Url}", url);
        var json = await httpClient.GetStringAsync(url, cancellationToken);

        // Return a summary to avoid overwhelming the LLM context
        using var doc = JsonDocument.Parse(json);
        var posts = doc.RootElement.EnumerateArray()
            .Select(p => new
            {
                id = p.GetProperty("id").GetInt32(),
                title = p.GetProperty("title").GetString()
            });
        return JsonSerializer.Serialize(posts, JsonOptions);
    }

    [McpServerTool, Description("Get all comments for a specific post.")]
    public async Task<string> GetComments(
        [Description("The post ID to retrieve comments for")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching comments for post {PostId}", postId);
        var json = await httpClient.GetStringAsync($"posts/{postId}/comments", cancellationToken);
        return json;
    }

    [McpServerTool, Description("Create a new post (simulated — JSONPlaceholder returns a fake ID).")]
    public async Task<string> CreatePost(
        [Description("User ID of the post author")] int userId,
        [Description("Title of the post")] string title,
        [Description("Body content of the post")] string body,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating post for user {UserId}", userId);
        var payload = new { userId, title, body };
        var response = await httpClient.PostAsJsonAsync("posts", payload, cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }
}

