using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// CRITICAL: all logging must go to stderr — stdout carries JSON-RPC protocol messages.
builder.Logging.AddConsole(o => o.LogToStandardErrorThreshold = LogLevel.Trace);

// Register HttpClient with a base address for the REST API.
// The DI container will inject this into any tool class that accepts HttpClient.
builder.Services.AddHttpClient<JsonPlaceholderTools>(client =>
{
    client.BaseAddress = new Uri("https://jsonplaceholder.typicode.com/");
    client.DefaultRequestHeaders.Add("Accept", "application/json");
});

// Configure the MCP server with stdio transport.
// WithToolsFromAssembly() discovers all classes marked [McpServerToolType].
builder.Services
    .AddMcpServer(options =>
    {
        options.ServerInfo = new() { Name = "ApiMcpServer", Version = "0.1.0" };
    })
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();

